class Solution {
public:
    ListNode* removeZeroSumSublists(ListNode* head) {
        ListNode* dummy = new ListNode(0);
        dummy->next = head;
        ListNode* curr = dummy;
        unordered_map<int, ListNode*> mp;
        while (curr) {
            mp[curr->val] = curr;
            curr = curr->next;
        }
        curr = dummy;
        int sum = 0;
        while (curr) {
            sum += curr->val;
            if (mp.find(sum) != mp.end()) {
                ListNode* start = mp[sum]->next;
                while (start) {
                    sum -= start->val;
                    start = start->next;
                }
            }
            curr = curr->next;
        }
        return dummy->next;
    }
};
